@Preview
@Composable
fun MainPage() {
    val isPreview = LocalInspectionMode.current
    val timetables = if (isPreview) remember {
        previewTimetables
    } else TimetableManager.timetables

    var editDialogState by rememberSaveable(saver = TimetableEntity.mutableStateSaver) { mutableStateOf(null) }
    var newTimetableDialogState by rememberSaveable(saver = TimetableEntity.mutableStateSaver) { mutableStateOf(null) }
    var errorDialogState by rememberSaveable { mutableStateOf<String?>(null) }
    Box(
        modifier = Modifier
            .fillMaxSize()
            .background(MaterialTheme.colorScheme.background)
            .statusBarsPadding(),
    ) {
        Column(
            modifier = Modifier.fillMaxWidth(),
            horizontalAlignment = Alignment.CenterHorizontally,
            verticalArrangement = Arrangement.spacedBy(12.dp)
        ) {
            Title()
            val state = rememberLazyListState()
            LazyColumn(
                state = state,
                verticalArrangement = Arrangement.spacedBy(6.dp)
            ) {
                items(items = timetables) { entity ->
                    TimetableEntry(
                        isPrimary = if(isPreview) false else TimetableManager.getPrimary()?.id == entity.id,
                        entity = entity,
                        onClickEdit = {
                            editDialogState = entity
                        }
                    )
                }
            }
            AddATimetable(
                onAdd = { entity ->
                    newTimetableDialogState = entity
                },
                onError = { error ->
                    errorDialogState = error
                }
            )
        }
        editDialogState?.let { entity ->
            EditTimetableDialog(
                entity, onCloseRequest = {
                    editDialogState = null
                })
        }
        newTimetableDialogState?.let { entity ->
            NewTimetableDialog (
                entity,
                onCloseRequest = {
                    newTimetableDialogState = null
                },
                onConfirm = {
                    TimetableManager.saveTimetable(entity)
                    newTimetableDialogState = null
                }
            )
        }
        errorDialogState?.let { error ->
            ErrorDialog(error, onDismissed = {
                errorDialogState = null
            })
        }
    }
}

@Composable
private fun TimetableEntry(
    isPrimary: Boolean,
    entity: TimetableEntity? = null,
    onClickEdit: () -> Unit = {}
) {
    Card(
        modifier = Modifier
            .fillMaxWidth()
            .padding(horizontal = 12.dp)
            .height(64.dp),
    ) {
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(12.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            CompositionLocalProvider(LocalMinimumInteractiveComponentSize provides 0.dp) {
                RadioButton(
                    selected = isPrimary,
                    onClick = {
                        entity?.let {
                            TimetableManager.setPrimary(entity)
                        }
                    },
                    modifier = Modifier.padding(start = 4.dp, end = 12.dp)
                )
            }
            Text(
                modifier = Modifier.weight(1f),
                text = entity?.nickname ?: entity?.timetable?.general?.title ?: "<title>"
            )
            Button(
                modifier = Modifier.size(40.dp, 40.dp),
                onClick = onClickEdit,
                contentPadding = PaddingValues.Zero
            ) {
                Icon(
                    painter = painterResource(R.drawable.settings_24px),
                    modifier = Modifier.size(24.dp, 24.dp),
                    contentDescription = "edit timetable \"${entity?.timetable?.general?.title ?: "<title>"}\""
                )
            }
        }
    }
}

@Composable
private fun Title() {
    Text(
        text = buildAnnotatedString {
            withStyle(SpanStyle(fontSize = 18.sp)) {
                append('g')
            }
            append("Rasp")
        }, color = MaterialTheme.colorScheme.onBackground, fontSize = 24.sp
    )
}


@Preview
@Composable
private fun EditTimetableDialog(
    entity: TimetableEntity? = null,
    onCloseRequest: () -> Unit = {},
) {
    var deletingInstead by rememberSaveable { mutableStateOf(false) }
    val timetableNicknameState = rememberTextFieldState(entity?.nickname ?: "")
    IconDialog(
        iconPainter = if(deletingInstead) painterResource(R.drawable.delete_24px) else painterResource(R.drawable.edit_24px),
        title = if(deletingInstead) "delete entry" else "edit entry",
        accentColor = if (deletingInstead) MaterialTheme.colorScheme.error else MaterialTheme.colorScheme.primary,
        contentDividersVisible = true,
        cancelButtonVisible = true,
        cancelButtonText = "cancel",
        onCancel = {
            if(deletingInstead) {
                deletingInstead = false
            } else {
                onCloseRequest()
            }
        },
        confirmButtonText = "confirm",
        onConfirm = {
            if(deletingInstead) {
                entity?.let {
                    onCloseRequest()
                    TimetableManager.deleteTimetable(it.id)
                }
            } else {
                entity?.let {
                    TimetableManager.saveTimetable(
                        TimetableEntity.build(
                            entity.url,
                            entity.json,
                            timetableNicknameState.text.toString()
                                .takeUnless { it.isBlank() }
                        )
                    )
                    onCloseRequest()
                }
            }
        },
        contentPadding = if(deletingInstead) PaddingValues(top = 12.dp, bottom = 14.dp) else PaddingValues(bottom = 2.dp)
    ) {
        if(deletingInstead) {
            Text(
                text = "Are you sure you want to delete",
            )
            Text(
                text = "\"${entity?.nickname ?: entity?.timetable?.general?.title ?: "<timetable name>"}\" ?",
                textAlign = TextAlign.Center,
                fontSize = 20.sp
            )
        } else {
            OutlinedTextField(
                state = timetableNicknameState,
                placeholder = {
                    Text(entity?.timetable?.general?.title ?: "placeholder nick")
                },
                label = {
                    Text("Nickname")
                }
            )
            Button(
                onClick = {
                    deletingInstead = true
                },
                colors = ButtonDefaults.buttonColors(
                    containerColor = Color.Transparent,
                    contentColor = MaterialTheme.colorScheme.error
                ),
                contentPadding = PaddingValues(vertical = 6.dp, horizontal = 12.dp),
                shape = RoundedCornerShape(8.dp)
            ) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(4.dp)
                ) {
                    Icon(
                        painter = painterResource(R.drawable.delete_24px),
                        contentDescription = null
                    )
                    Text(text = "Delete")
                }
            }

        }
    }
}


@Composable
private fun AddATimetable(
    onAdd: (TimetableEntity) -> Unit = {},
    onError: (String) -> Unit = {}
) {
    val isPreview = LocalInspectionMode.current

    val state = rememberTextFieldState()
    var isError by remember { mutableStateOf(false) }
    LaunchedEffect(state.text) {
        isError = false
    }

    var isFetching by rememberSaveable { mutableStateOf(false) }
    val scope = rememberCoroutineScope()
    Row(
        modifier = Modifier
            .fillMaxWidth()
            .wrapContentHeight()
            .padding(horizontal = 21.dp),
        verticalAlignment = Alignment.CenterVertically,
        horizontalArrangement = Arrangement.spacedBy(12.dp)
    ) {
        OutlinedTextField(
            modifier = Modifier
                .weight(1f),
            state = state,
            isError = isError,
            placeholder = {
                Text("https://raspored.rs/pub/?pid=XYZ")
            },
            label = {
                Text("Add a timetable")
            },
            lineLimits = TextFieldLineLimits.SingleLine
        )
        Button(
            onClick = {
                if (isFetching) return@Button
                val url = state.text.toString()

                if (!url.matches(GlobalRegex.URL_REGEX_NAMED)) {
                    isError = true
                    return@Button
                }

                isFetching = true
                scope.launch {
                    withContext(Dispatchers.IO) {
                        try {
                            if(isPreview) {
                                delay(2000)
                                onAdd(previewTimetables.first())
                            } else {
                                val json = UrlProcessor.fetchJson(url)
                                onAdd(
                                    TimetableEntity.build(
                                        UrlProcessor.removeNonIdParameters(url),
                                        json
                                    )
                                )
                            }
                        } catch (e: Exception) {
                            onError(e.message ?: "no info was provided")
                            return@withContext
                        } finally {
                            isFetching = false
                        }
                    }
                }
            },
            modifier = Modifier.size(46.dp, 46.dp),
            contentPadding = PaddingValues.Zero
        ) {
            if (isFetching) {
                CircularProgressIndicator(
                    modifier = Modifier
                        .fillMaxSize()
                        .padding(10.dp),
                    strokeWidth = 3.dp,
                    color = MaterialTheme.colorScheme.onPrimary
                )
            } else {
                Icon(
                    painter = painterResource(R.drawable.add_24px),
                    tint = MaterialTheme.colorScheme.onPrimary,
                    contentDescription = "add timetable icon",
                )
            }
        }
    }
}

@Composable
private fun ErrorDialog(
    error: String,
    onDismissed: () -> Unit
) {
    IconDialog(
        iconPainter = painterResource(R.drawable.error_24px),
        title = "an error occurred.",
        cancelButtonVisible = false,
        cancelButtonText = "",
        onCancel = onDismissed,
        confirmButtonText = "ok :(",
        onConfirm = onDismissed,
        content = {
            Text(error)
        },
    )
}